const { ipcRenderer } = require('electron');

// DOM 元素
const urlInput = document.getElementById('urlInput');
const pasteBtn = document.getElementById('pasteBtn');
const platformIndicator = document.getElementById('platformIndicator');
const progressFill = document.getElementById('progressFill');
const statusText = document.getElementById('statusText');
const extractBtn = document.getElementById('extractBtn');
const downloadBtn = document.getElementById('downloadBtn');
const infoModal = document.getElementById('infoModal');
const modalBody = document.getElementById('modalBody');
const closeModal = document.getElementById('closeModal');

// 状态变量
let currentMode = 'merge';
let isProcessing = false;

// 检测平台
function detectPlatform(url) {
    url = url.toLowerCase();
    if (url.includes('youtube.com') || url.includes('youtu.be')) {
        return 'youtube';
    }
    if (url.includes('douyin.com') || url.includes('iesdouyin.com')) {
        return 'douyin';
    }
    if (url.includes('tiktok.com')) {
        return 'tiktok';
    }
    if (url.includes('bilibili.com')) {
        return 'bilibili';
    }
    return 'unknown';
}

// URL 输入变化检测
urlInput.addEventListener('input', () => {
    const platform = detectPlatform(urlInput.value);
    if (platform === 'youtube') {
        platformIndicator.textContent = '📡 检测到: YouTube';
        platformIndicator.style.color = '#ff0000';
    } else if (platform === 'douyin') {
        platformIndicator.textContent = '🎵 检测到: 抖音';
        platformIndicator.style.color = '#00d1ff';
    } else if (platform === 'tiktok') {
        platformIndicator.textContent = '🎵 检测到: TikTok';
        platformIndicator.style.color = '#00f2ea';
    } else if (platform === 'bilibili') {
        platformIndicator.textContent = '📺 检测到: Bilibili';
        platformIndicator.style.color = '#fb7299';
    } else if (urlInput.value && !urlInput.value.includes('粘贴')) {
        platformIndicator.textContent = '⚠️ 不支持的链接';
        platformIndicator.style.color = '#ff6600';
    } else {
        platformIndicator.textContent = '📡 等待输入...';
        platformIndicator.style.color = 'rgba(255, 255, 255, 0.5)';
    }
});

// 从粘贴文本中提取 URL（处理分享文本如 "【标题】 https://xxx"）
function extractUrl(text) {
    const match = text.match(/https?:\/\/[^\s"'<>]+/);
    return match ? match[0] : text.trim();
}

// 粘贴按钮
pasteBtn.addEventListener('click', async () => {
    try {
        const text = await navigator.clipboard.readText();
        urlInput.value = extractUrl(text);
        urlInput.dispatchEvent(new Event('input'));
        statusText.textContent = '已粘贴链接';
    } catch (err) {
        statusText.textContent = '剪贴板为空';
    }
});

// 模式选择按钮
document.querySelectorAll('.mode-btn').forEach(btn => {
    btn.addEventListener('click', () => {
        document.querySelectorAll('.mode-btn').forEach(b => b.classList.remove('active'));
        btn.classList.add('active');
        currentMode = btn.dataset.mode;
    });
});

// 平台名称映射
const platformNames = {
    youtube: 'YouTube',
    douyin: '抖音',
    tiktok: 'TikTok',
    bilibili: 'Bilibili'
};

// 提取视频信息
extractBtn.addEventListener('click', async () => {
    if (isProcessing) return;

    const url = urlInput.value.trim();
    if (!url || url.includes('粘贴')) {
        alert('请输入有效的视频链接！');
        return;
    }

    const platform = detectPlatform(url);
    if (platform === 'unknown') {
        alert('请输入有效的视频链接！\n\n支持的平台：\n• YouTube\n• 抖音\n• TikTok\n• Bilibili');
        return;
    }

    isProcessing = true;
    extractBtn.disabled = true;
    statusText.textContent = `正在解析 ${platformNames[platform]} 视频信息...`;

    try {
        const result = await ipcRenderer.invoke('extract-info', url);
        if (result.success) {
            modalBody.textContent = result.info;
            infoModal.classList.add('show');
            statusText.textContent = '信息获取成功！';
        } else {
            statusText.textContent = '获取信息失败';
            alert('获取视频信息失败！\n\n' + result.error);
        }
    } catch (err) {
        statusText.textContent = '发生错误';
        alert('获取信息出错：' + err.message);
    } finally {
        isProcessing = false;
        extractBtn.disabled = false;
    }
});

// 开始下载
downloadBtn.addEventListener('click', async () => {
    if (isProcessing) return;

    const url = urlInput.value.trim();
    if (!url || url.includes('粘贴')) {
        alert('请输入有效的视频链接！');
        return;
    }

    const platform = detectPlatform(url);
    if (platform === 'unknown') {
        alert('请输入有效的视频链接！');
        return;
    }

    isProcessing = true;
    downloadBtn.disabled = true;
    progressFill.style.width = '0%';

    statusText.textContent = `正在解析 ${platformNames[platform]} 视频...`;

    try {
        const result = await ipcRenderer.invoke('start-download', url, currentMode);
        if (result.success) {
            progressFill.style.width = '100%';
            statusText.textContent = '下载完成！';
            alert('视频已下载到桌面！');
        } else {
            progressFill.style.width = '0%';
            statusText.textContent = '下载失败';
            alert('下载失败！\n\n' + result.error);
        }
    } catch (err) {
        progressFill.style.width = '0%';
        statusText.textContent = '发生错误';
        alert('下载出错：' + err.message);
    } finally {
        isProcessing = false;
        downloadBtn.disabled = false;
    }
});

// 监听下载进度
ipcRenderer.on('download-progress', (event, progress) => {
    progressFill.style.width = progress.percent + '%';
    statusText.textContent = `下载中... ${progress.percent.toFixed(0)}%`;
});

// 关闭弹窗
closeModal.addEventListener('click', () => {
    infoModal.classList.remove('show');
});

infoModal.addEventListener('click', (e) => {
    if (e.target === infoModal) {
        infoModal.classList.remove('show');
    }
});

// 清除占位符
urlInput.addEventListener('focus', () => {
    if (urlInput.value.includes('粘贴')) {
        urlInput.value = '';
    }
});

* {
    margin: 0;
    padding: 0;
    box-sizing: border-box;
}

body {
    font-family: 'Microsoft YaHei UI', -apple-system, BlinkMacSystemFont, sans-serif;
    overflow-y: auto;
    min-height: 100vh;
    background: #0a0a1a;
}

/* 极光渐变背景 */
.aurora-bg {
    position: fixed;
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
    z-index: -1;
    background: linear-gradient(135deg, #0a0a1a 0%, #1a0a2e 50%, #0a1a2e 100%);
}

.aurora-blob {
    position: absolute;
    border-radius: 50%;
    filter: blur(80px);
    opacity: 0.6;
    animation: float 20s ease-in-out infinite;
}

.blob-1 {
    width: 500px;
    height: 500px;
    background: linear-gradient(45deg, #ff6b9d, #c04868);
    top: -200px;
    left: -100px;
    animation-delay: 0s;
}

.blob-2 {
    width: 400px;
    height: 400px;
    background: linear-gradient(45deg, #8a2be2, #5d26c1);
    top: 50%;
    right: -150px;
    animation-delay: -5s;
}

.blob-3 {
    width: 450px;
    height: 450px;
    background: linear-gradient(45deg, #00c8ff, #06b6d4);
    bottom: -150px;
    left: 30%;
    animation-delay: -10s;
}

.blob-4 {
    width: 350px;
    height: 350px;
    background: linear-gradient(45deg, #ff6b9d, #8a2be2);
    top: 40%;
    left: 40%;
    animation-delay: -15s;
}

@keyframes float {
    0%, 100% {
        transform: translate(0, 0) scale(1);
    }
    25% {
        transform: translate(50px, -50px) scale(1.1);
    }
    50% {
        transform: translate(-30px, 30px) scale(0.9);
    }
    75% {
        transform: translate(-50px, -30px) scale(1.05);
    }
}

