.paste-btn {
    width: 50px;
    height: 50px;
    font-size: 20px;
    background: linear-gradient(135deg, #8a2be2, #5d26c1);
    border: none;
    border-radius: 12px;
    cursor: pointer;
    transition: all 0.3s ease;
}

.paste-btn:hover {
    transform: scale(1.05);
    box-shadow: 0 5px 20px rgba(138, 43, 226, 0.4);
}

.platform-indicator {
    margin-top: 10px;
    font-size: 12px;
    color: rgba(255, 255, 255, 0.5);
}

/* 模式选择 */
