    background: linear-gradient(135deg, rgba(255, 107, 157, 0.3), rgba(138, 43, 226, 0.3));
    border-color: #ff6b9d;
}

.mode-icon {
    font-size: 24px;
}

.mode-text {
    font-size: 12px;
    color: #ffffff;
}

/* 进度条 */
