    margin-bottom: 20px;
}

.progress-bar {
    height: 10px;
    background: rgba(26, 10, 42, 0.8);
    border-radius: 10px;
    overflow: hidden;
    margin-bottom: 10px;
}

.progress-fill {
    height: 100%;
    width: 0%;
    background: linear-gradient(90deg, #ff6b9d, #8a2be2, #00c8ff);
    border-radius: 10px;
    transition: width 0.3s ease;
}

.status-text {
    font-size: 12px;
    color: rgba(255, 255, 255, 0.6);
    text-align: center;
}

/* 操作按钮 */
.action-buttons {
    display: flex;
    flex-direction: column;
    gap: 12px;
    margin-bottom: 15px;
}

.btn {
    display: flex;
    align-items: center;
    justify-content: center;
    gap: 12px;
    padding: 18px;
    font-size: 16px;
    font-weight: bold;
    border: none;
    border-radius: 14px;
    cursor: pointer;
    transition: all 0.3s ease;
}

.btn-icon {
    font-size: 20px;
}

.btn-text {
    color: #ffffff;
}

.btn-primary {
    background: linear-gradient(135deg, #ff3366, #ff6b9d);
    box-shadow: 0 4px 20px rgba(255, 51, 102, 0.4);
}

.btn-primary:hover {
    transform: translateY(-2px);
    box-shadow: 0 6px 30px rgba(255, 51, 102, 0.6);
}

.btn-info {
    background: linear-gradient(135deg, #00aacc, #06b6d4);
    box-shadow: 0 4px 20px rgba(0, 170, 204, 0.4);
}

.btn-info:hover {
