    box-shadow: 0 6px 30px rgba(0, 170, 204, 0.6);
}

.btn:disabled {
    opacity: 0.5;
    cursor: not-allowed;
    transform: none !important;
}

/* 信息框 */
.info-box {
    padding: 15px;
    background: rgba(26, 10, 42, 0.6);
    border-radius: 12px;
}

.info-box p {
