}

.modal-content {
    width: 90%;
    max-width: 500px;
    max-height: 80vh;
    overflow: auto;
}

.modal-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-bottom: 20px;
}

.modal-header h2 {
    font-size: 20px;
    color: #ff6b9d;
}

.close-btn {
    width: 35px;
    height: 35px;
    font-size: 18px;
    background: rgba(255, 255, 255, 0.1);
    border: none;
    border-radius: 50%;
    color: #ffffff;
    cursor: pointer;
    transition: all 0.3s ease;
}

.close-btn:hover {
    background: rgba(255, 107, 157, 0.5);
}

.modal-body {
    color: #ffffff;
    line-height: 1.8;
    font-size: 14px;
    white-space: pre-wrap;
}

/* 滚动条 */
